bitflags! {
    /// socket type
    pub struct SocketType: u32 {
        /// for TCP
        const SOCK_STREAM = 1 << 0;
        /// for UDP
        const SOCK_DGRAM = 1 << 1;
        /// for raw sockets (ICMP etc)
        const SOCK_RAW = 1 << 2;
        /// unused now
        const SOCK_CLOEXEC = 1 << 19;
        const SOCK_NONBLOCK = 0x800;
    }
}

