                    buffer.set_len(left_bytes.min(BUFFER_SIZE));
                }
                let read_size = in_file.read(unsafe { off_in.as_mut() }, buffer.as_mut_slice());
                if (read_size as isize) < 0 {
                    let errno = read_size as isize;
                    return errno;
                } else if read_size == 0 {
                    break;
                }
                unsafe {
                    buffer.set_len(read_size);
                }
                buffer.as_slice()
            }
