        NET_INTERFACE.poll();
        let ret = NET_INTERFACE.inner_handler(|inner| {
            inner.sockets.get_mut::<icmp::Socket>(self.socket_handler).can_recv()
        });
        NET_INTERFACE.poll();
        ret
    }
    fn w_ready(&self) -> bool {
        NET_INTERFACE.poll();
        let ret = NET_INTERFACE.inner_handler(|inner| {
            inner.sockets.get_mut::<icmp::Socket>(self.socket_handler).can_send()
        });
        NET_INTERFACE.poll();
        ret
    }
